import React, { useState } from 'react';
import './App.css';
//import { auth } from './components/firebase_setup';

import Home from './Pages/Home';
import SignIn from './Pages/SignIn';
import Feed from './Pages/Feed';


//line {user ? <frontpage /> : <SignIn />} is basically like if the user is logged in show frontpage, if not show signIn
function App() {
  const user = localStorage.getItem("email");
  return (
    <div className="App">
      <AuthProvider>
      {userLoggedIn ? <HomePage /> : <Signin />}
      </AuthProvider>
    </div>
  );
}


export default App;
